sql:
SELECT open, close 
FROM market_data 
WHERE date = (SELECT MIN(date) FROM market_data);

external_knowledge:
- 'Crown jewel cryptocurrency' refers to the cryptocurrency with the highest market capitalization; 
- 'reached the highest treasure' means having the highest total profit; 
- 'most valuable digital riches' refers to the top 3 cryptocurrencies with the highest current market capitalization.

sql:
SELECT SUM(profit_loss) AS total_profit_loss
FROM user_portfolios
WHERE user_id = (SELECT user_id FROM users WHERE username = 'bob_williams');

SELECT AVG(purchase_price) 
FROM user_portfolios
WHERE crypto_id = (SELECT crypto_id FROM cryptocurrencies WHERE name = 'Ethereum');

external_knowledge:
- 'Champions of the cryptocurrency world' refers to the cryptocurrencies with the highest market capitalization; 
- 'Active players' means cryptocurrencies that are currently active (is_active = 1); 
- 'Highest-ever market capitalization crowns' refers to the maximum market capitalization values for each active cryptocurrency.
